class Dedupe:
    def __init__(self):
        self.seen = set()

    def add(self, x):
        self.seen.add(x)

    def compact(self):
        # BUG: mutating set while iterating it
        for item in self.seen:
            if item.startswith('_'):
                self.seen.discard(item)
        return self.seen


def dedupe(items):
    d = Dedupe()
    for x in items:
        d.add(x)
    return d.compact()


def main():
    items = ['a', '_private', 'b', '_hidden', 'c']
    out = dedupe(items)
    print(out)


if __name__ == '__main__':
    main()
